namespace sv_5b23772605334984a46f017acb3deae3.Services;

public class WarehouseInfo
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

/// <summary>
/// Scoped per-circuit state that holds the current warehouse selection and
/// the latest low-stock alert count. Because Blazor Server scopes DI to the
/// SignalR circuit, each browser tab / user gets an independent instance.
/// </summary>
public class WarehouseState
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new() { Id = "WH-A", Name = "Warehouse A" },
        new() { Id = "WH-B", Name = "Warehouse B" },
        new() { Id = "WH-C", Name = "Warehouse C" },
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;
    private int _lowStockCount;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId).Name;

    public int LowStockCount => _lowStockCount;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        _lowStockCount = 0; // reset until next poll
        NotifyStateChanged();
    }

    public void SetLowStockCount(int count)
    {
        _lowStockCount = count;
        NotifyStateChanged();
    }

    private void NotifyStateChanged() => OnChange?.Invoke();
}

namespace sv_5b23772605334984a46f017acb3deae3.Services;

/// <summary>
/// Simulates a database query that returns the number of items below
/// minimum stock levels for a given warehouse.
/// </summary>
public class InventoryAlertService
{
    private readonly Random _random = new();

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate async DB call
        int count = _random.Next(0, 16); // 0–15 inclusive
        return Task.FromResult(count);
    }
}

@using sv_5b23772605334984a46f017acb3deae3.Services
@inject WarehouseState State
@implements IDisposable

<div class="warehouse-selector">
    <label class="me-2 mb-0 text-muted" for="warehouseSelect">Warehouse:</label>
    <select id="warehouseSelect"
            class="form-select form-select-sm d-inline-block w-auto"
            value="@State.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseState.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    protected override void OnInitialized()
    {
        State.OnChange += StateHasChanged;
    }

    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        if (!string.IsNullOrEmpty(id))
        {
            State.SetWarehouse(id);
        }
    }

    public void Dispose()
    {
        State.OnChange -= StateHasChanged;
    }
}

@using sv_5b23772605334984a46f017acb3deae3.Services
@inject WarehouseState State
@implements IDisposable

@if (State.LowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-2" title="Low-stock items">
        @State.LowStockCount
    </span>
}

@code {
    protected override void OnInitialized()
    {
        State.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        State.OnChange -= StateHasChanged;
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@using sv_5b23772605334984a46f017acb3deae3.Services
@inject WarehouseState State
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard – @State.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">@State.CurrentWarehouseName</h5>
        <p class="card-text">
            Warehouse ID: <strong>@State.CurrentWarehouseId</strong>
        </p>
    </div>
</div>

<div class="row">
    <div class="col-md-4">
        <div class="card text-bg-@(State.LowStockCount > 0 ? "danger" : "success")">
            <div class="card-body text-center">
                <h2 class="display-4">@State.LowStockCount</h2>
                <p class="card-text">Low-Stock Alerts</p>
                <small class="opacity-75">Refreshes every 10 seconds</small>
            </div>
        </div>
    </div>
</div>

@if (_lastChecked.HasValue)
{
    <p class="text-muted mt-3">
        Last checked: @_lastChecked.Value.ToString("HH:mm:ss")
    </p>
}

@code {
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private DateTime? _lastChecked;

    protected override async Task OnInitializedAsync()
    {
        State.OnChange += StateHasChanged;

        // Initial fetch
        await PollAlerts();

        // Start background polling
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoop(_cts.Token);
    }

    private async Task PollLoop(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                await PollAlerts();
                await InvokeAsync(StateHasChanged);
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on dispose
        }
    }

    private async Task PollAlerts()
    {
        var count = await AlertService.GetLowStockCountAsync(State.CurrentWarehouseId);
        State.SetLowStockCount(count);
        _lastChecked = DateTime.Now;
    }

    public void Dispose()
    {
        State.OnChange -= StateHasChanged;
        _cts?.Cancel();
        _cts?.Dispose();
        _timer?.Dispose();
    }
}

